t.script:
(function() {
    var btnSearch = document.getElementById('btn_search_farmer');
    var searchFarmerId = document.getElementById('search_farmer_id');
    var searchNationalId = document.getElementById('search_national_id');
    var resultsDiv = document.getElementById('farmer_search_results');
    var resultsList = document.getElementById('farmer_results_list');
    var createCard = document.getElementById('create_request_card');
    var formFarmerId = document.getElementById('form_farmer_id');
    var selectedFarmerName = document.getElementById('selected_farmer_name');
    var btnClear = document.getElementById('btn_clear_farmer');
    var btnSubmitDisabledReason = document.getElementById('btn_submit_disabled_reason');
    var consentForm = document.getElementById('consent_request_form');
    var purposeInput = document.getElementById('purpose');
    var purposeError = document.getElementById('purpose_error');
    var dataFieldInputs = consentForm ? consentForm.querySelectorAll('input[name="allowed_data_field_ids"]') : [];
    var dataFieldsError = document.getElementById('data_fields_error');
    var attachmentInput = consentForm ? consentForm.querySelector('input[name="attachment"]') : null;
    var attachmentError = document.getElementById('attachment_error');
    var cameraDataInput = document.getElementById('camera_capture_data');
    var cameraTakenAtInput = document.getElementById('camera_capture_taken_at');
    var cameraLatitudeInput = document.getElementById('camera_capture_latitude');
    var cameraLongitudeInput = document.getElementById('camera_capture_longitude');
    var cameraAccuracyInput = document.getElementById('camera_capture_accuracy');
    var cameraInfo = document.getElementById('camera_capture_info');
    var cameraError = document.getElementById('camera_error');
    var cameraPreview = document.getElementById('camera_capture_preview');
    var cameraVideo = document.getElementById('camera_live_preview');
    var cameraCanvas = document.getElementById('camera_canvas');
    var btnOpenCamera = document.getElementById('btn_open_camera');
    var btnTakeCameraPhoto = document.getElementById('btn_take_camera_photo');
    var btnCloseCamera = document.getElementById('btn_close_camera');
    var btnRetakeCameraPhoto = document.getElementById('btn_retake_camera_photo');
    var tableWrap = document.getElementById('consent_table_wrap');
    var tableBody = document.getElementById('consent_request_table_body');
    var tableLoader = document.getElementById('consent_table_loader');
    var tableEnd = document.getElementById('consent_table_end');
    var maxAttachmentSize = 10 * 1024 * 1024;
    var cameraStream = null;
    var tableScrollTicking = false;
    var errorMessagesByCode = {
        access_denied: 'Access denied. Please contact your administrator.',
        missing_farmer: 'Please search and select a farmer first.',
        invalid_farmer: 'Invalid farmer selected.',
        farmer_not_found: 'Farmer not found.',
        missing_purpose: 'Purpose is required.',
        missing_data_fields: 'No valid data fields selected. Configure partner data fields first.',
        missing_attachment: 'Attachment is required.',
        attachment_too_large: 'Attachment must be 10MB or smaller.',
        camera_too_large: 'Camera photo must be 10MB or smaller.',
        invalid_camera_data: 'Invalid camera image data.',
        invalid_camera_timestamp: 'Invalid camera timestamp.',
        invalid_camera_location: 'Invalid camera capture location.',
        server_error: 'An error occurred while creating the consent request.'
    };

    function toInt(value, fallbackValue) {
        var parsed = parseInt(value, 10);
        return Number.isFinite(parsed) ? parsed : fallbackValue;
    }

    var tableState = {
        total: toInt(tableWrap && tableWrap.getAttribute('data-total'), 0),
        limit: toInt(tableWrap && tableWrap.getAttribute('data-limit'), 10),
        offset: toInt(tableWrap && tableWrap.getAttribute('data-offset'), 0),
        loading: false,
        done: false
    };

    function formatDateForOdoo(dateObj) {
        function pad(v) { return String(v).padStart(2, '0'); }
        return dateObj.getFullYear() + '-' + pad(dateObj.getMonth() + 1) + '-' + pad(dateObj.getDate()) + ' ' +
            pad(dateObj.getHours()) + ':' + pad(dateObj.getMinutes()) + ':' + pad(dateObj.getSeconds());
    }

    function setPurposeError(message) {
        if (!purposeError) return;
        if (message) {
            purposeError.textContent = message;
            purposeError.classList.remove('d-none');
        } else {
            purposeError.textContent = '';
            purposeError.classList.add('d-none');
        }
    }

    function setDataFieldsError(message) {
        if (!dataFieldsError) return;
        if (message) {
            dataFieldsError.textContent = message;
            dataFieldsError.classList.remove('d-none');
        } else {
            dataFieldsError.textContent = '';
            dataFieldsError.classList.add('d-none');
        }
    }

    function setAttachmentError(message) {
        if (!attachmentError) return;
        if (message) {
            attachmentError.textContent = message;
            attachmentError.classList.remove('d-none');
        } else {
            attachmentError.textContent = '';
            attachmentError.classList.add('d-none');
        }
    }

    function setCameraError(message) {
        if (!cameraError) return;
        if (message) {
            cameraError.textContent = message;
            cameraError.classList.remove('d-none');
        } else {
            cameraError.textContent = '';
            cameraError.classList.add('d-none');
        }
    }

    function showServiceProviderModal(message, isError) {
        var modalEl = document.getElementById('successModal');
        if (!modalEl || !message) return;
        var imgEl = modalEl.querySelector('.popup_img');
        var titleEl = modalEl.querySelector('h4');
        var msgEl = modalEl.querySelector('.popup_msg');
        if (imgEl) {
            imgEl.src = isError
                ? '/g2p_ati_service_provider_portal/static/src/img/no.png'
                : '/g2p_ati_service_provider_portal/static/src/img/ok.png';
        }
        if (titleEl) {
            titleEl.textContent = isError ? 'Error' : 'Success!';
        }
        if (msgEl) {
            msgEl.textContent = message;
        }
        if (window.jQuery && window.jQuery.fn && window.jQuery.fn.modal) {
            window.jQuery('#successModal').modal('show');
        } else if (window.bootstrap && window.bootstrap.Modal) {
            window.bootstrap.Modal.getOrCreateInstance(modalEl).show();
        }
    }

    function hasSelectedDataField() {
        if (!dataFieldInputs || !dataFieldInputs.length) return false;
        for (var i = 0; i < dataFieldInputs.length; i++) {
            if (dataFieldInputs[i].checked) return true;
        }
        return false;
    }

    function stopCameraStream() {
        if (!cameraStream) return;
        var tracks = cameraStream.getTracks ? cameraStream.getTracks() : [];
        for (var i = 0; i < tracks.length; i++) {
            tracks[i].stop();
        }
        cameraStream = null;
        if (cameraVideo) {
            cameraVideo.pause();
            cameraVideo.srcObject = null;
        }
    }

    function showCameraButtons(isLive, hasCapture) {
        if (btnTakeCameraPhoto) btnTakeCameraPhoto.classList.toggle('d-none', !isLive);
        if (btnCloseCamera) btnCloseCamera.classList.toggle('d-none', !isLive);
        if (btnRetakeCameraPhoto) btnRetakeCameraPhoto.classList.toggle('d-none', isLive || !hasCapture);
    }

    function clearCameraLocation() {
        if (cameraLatitudeInput) cameraLatitudeInput.value = '';
        if (cameraLongitudeInput) cameraLongitudeInput.value = '';
        if (cameraAccuracyInput) cameraAccuracyInput.value = '';
    }

    function getCameraLocation(callback) {
        if (!navigator.geolocation) {
            clearCameraLocation();
            callback(false);
            return;
        }
        navigator.geolocation.getCurrentPosition(
            function(position) {
                if (cameraLatitudeInput) cameraLatitudeInput.value = String(position.coords.latitude);
                if (cameraLongitudeInput) cameraLongitudeInput.value = String(position.coords.longitude);
                if (cameraAccuracyInput) cameraAccuracyInput.value = String(position.coords.accuracy || '');
                callback(true);
            },
            function() {
                clearCameraLocation();
                callback(false);
            },
            {
                enableHighAccuracy: true,
                timeout: 8000,
                maximumAge: 0
            }
        );
    }

    function htmlEscape(value) {
        return String(value == null ? '' : value)
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&#39;');
    }

    function normalizeStatus(status) {
        return String(status || '').toLowerCase().replace(/[^a-z0-9_-]/g, '');
    }

    function statusIcon(status) {
        var normalized = normalizeStatus(status);
        if (normalized === 'approved') return '&#10003;';
        if (normalized === 'pending') return '&#128336;';
        if (normalized === 'rejected' || normalized === 'denied') return '&#10005;';
        if (normalized === 'expired' || normalized === 'revoked') return '&#128336;';
        return '';
    }

    function buildTableRowHtml(row) {
        var reqId = htmlEscape(row.request_id || '');
        var farmerName = htmlEscape(row.farmer_name || '');
        var consentType = htmlEscape(row.consent_type || '');
        var createdAt = htmlEscape(row.created_at || '');
        var statusValue = row.status || '';
        var normalizedStatus = normalizeStatus(statusValue);
        var statusText = htmlEscape(statusValue || '');
        var statusHtml = '<span class="consent_status_badge consent_status_' + normalizedStatus + '">' + statusIcon(statusValue) + statusText + '</span>';
        var reviewUrl = row.review_url || ('/consent/management/review/' + String(row.id || '') + '?view=table#review_request');
        var reviewHref = htmlEscape(reviewUrl);
        return '<tr>' +
            '<td class="consent_table_id">' + reqId + '</td>' +
            '<td><span class="fw-semibold consent_farmer_name">' + farmerName + '</span></td>' +
            '<td>' + consentType + '</td>' +
            '<td>' + statusHtml + '</td>' +
            '<td>' + createdAt + '</td>' +
            '<td><a href="' + reviewHref + '" class="btn btn-sm btn-outline-secondary">Review</a></td>' +
            '</tr>';
    }

    function setTableLoaderVisible(isVisible) {
        if (!tableLoader) return;
        tableLoader.classList.toggle('d-none', !isVisible);
    }

    function setTableEndVisible(isVisible) {
        if (!tableEnd) return;
        tableEnd.classList.toggle('d-none', !isVisible);
    }

    function shouldFetchTableRows() {
        if (!tableWrap || !tableBody || tableState.loading || tableState.done) return false;
        var viewportHeight = window.innerHeight || document.documentElement.clientHeight || 0;
        var rect = tableWrap.getBoundingClientRect();
        return rect.bottom <= viewportHeight + 180;
    }

    function fetchTableRows(offset, limit, done) {
        var req = new XMLHttpRequest();
        req.open('POST', '/consent/management/table_fetch');
        req.setRequestHeader('Content-Type', 'application/json');
        req.setRequestHeader('Accept', 'application/json');
        req.onload = function() {
            var raw = {};
            try { raw = JSON.parse(req.responseText || '{}'); } catch (e) {}
            var res = raw.result != null ? raw.result : raw;
            if (req.status >= 200 && req.status < 300 && res && res.success && res.data) {
                done(null, res.data);
                return;
            }
            done(new Error('Unable to fetch more consent requests.'));
        };
        req.onerror = function() {
            done(new Error('Network error while fetching consent requests.'));
        };
        req.send(JSON.stringify({
            jsonrpc: '2.0',
            method: 'call',
            params: { offset: offset, limit: limit },
            id: Date.now()
        }));
    }

    function markTableDone() {
        tableState.done = true;
        setTableLoaderVisible(false);
        setTableEndVisible(true);
    }

    function loadMoreTableRows() {
        if (!tableWrap || !tableBody || tableState.loading || tableState.done) return;
        if (tableState.total > 0 && tableState.offset >= tableState.total) {
            markTableDone();
            return;
        }

        tableState.loading = true;
        setTableLoaderVisible(true);
        setTableEndVisible(false);

        fetchTableRows(tableState.offset, tableState.limit, function(error, data) {
            tableState.loading = false;
            setTableLoaderVisible(false);

            if (error || !data) {
                return;
            }

            tableState.total = toInt(data.total, tableState.total);
            var rows = Array.isArray(data.rows) ? data.rows : [];
            for (var i = 0; i < rows.length; i++) {
                tableBody.insertAdjacentHTML('beforeend', buildTableRowHtml(rows[i]));
            }
            tableState.offset += rows.length;
            if (tableWrap) {
                tableWrap.setAttribute('data-offset', String(tableState.offset));
            }

            if (!rows.length || (tableState.total > 0 && tableState.offset >= tableState.total)) {
                markTableDone();
                return;
            }

            if (shouldFetchTableRows()) {
                loadMoreTableRows();
            }
        });
    }

    function onTableScroll() {
        if (tableScrollTicking) return;
        tableScrollTicking = true;
        window.requestAnimationFrame(function() {
            tableScrollTicking = false;
            if (shouldFetchTableRows()) {
                loadMoreTableRows();
            }
        });
    }

    function initInfiniteTable() {
        if (!tableWrap || !tableBody) return;
        tableState.limit = Math.max(1, tableState.limit);
        if (tableState.total > 0 && tableState.offset >= tableState.total) {
            markTableDone();
            return;
        }
        window.addEventListener('scroll', onTableScroll, { passive: true });
        window.addEventListener('resize', onTableScroll);
        onTableScroll();
    }

    function searchFarmers() {
        var singleQuery = (searchNationalId && searchNationalId.value) ? searchNationalId.value.trim() : '';
        if (!singleQuery) {
            resultsDiv.classList.add('d-none');
            return;
        }
        var req = new XMLHttpRequest();
        req.open('POST', '/consent/search_farmer');
        req.setRequestHeader('Content-Type', 'application/json');
        req.setRequestHeader('Accept', 'application/json');
        req.onload = function() {
            var raw = {};
            try { raw = JSON.parse(req.responseText || '{}'); } catch (e) {}
            var res = raw.result != null ? raw.result : raw;
            if (res.success && res.data && res.data.farmers && res.data.farmers.length) {
                resultsList.innerHTML = '';
                res.data.farmers.forEach(function(f) {
                    var regIds = (f.reg_ids && f.reg_ids.length) ? f.reg_ids.join(', ') : '';
                    var div = document.createElement('div');
                    div.className = 'consent_farmer_result_item';
                    var left = document.createElement('div');
                    left.innerHTML = (f.name || '') + ' <span class="text-muted small">(Farmer ID: ' + (f.farmer_id || '—') + (regIds ? ' · ' + regIds : '') + ')</span>';
                    div.appendChild(left);
                    var btn = document.createElement('button');
                    btn.type = 'button';
                    btn.className = 'btn btn-sm consent_btn_primary select-farmer';
                    btn.setAttribute('data-id', f.id);
                    btn.setAttribute('data-name', f.name || '');
                    btn.textContent = 'Select';
                    btn.addEventListener('click', function() {
                        formFarmerId.value = this.getAttribute('data-id');
                        selectedFarmerName.textContent = this.getAttribute('data-name') || '—';
                        createCard.classList.remove('d-none');
                    });
                    div.appendChild(btn);
                    resultsList.appendChild(div);
                });
                resultsDiv.classList.remove('d-none');
            } else {
                resultsList.innerHTML = '<p class="text-muted mb-0">No farmers found.</p>';
                resultsDiv.classList.remove('d-none');
            }
        };
        req.send(JSON.stringify({
            jsonrpc: '2.0',
            method: 'call',
            params: { query: singleQuery },
            id: Date.now()
        }));
    }

    if (btnSearch) btnSearch.addEventListener('click', searchFarmers);
    if (searchNationalId) searchNationalId.addEventListener('keydown', function(e) { if (e.key === 'Enter') { e.preventDefault(); searchFarmers(); } });
    if (btnClear) {
        btnClear.addEventListener('click', function() {
            formFarmerId.value = '';
            selectedFarmerName.textContent = '—';
            createCard.classList.add('d-none');
            stopCameraStream();
            if (cameraDataInput) cameraDataInput.value = '';
            if (cameraTakenAtInput) cameraTakenAtInput.value = '';
            clearCameraLocation();
            if (cameraPreview) {
                cameraPreview.src = '';
                cameraPreview.classList.add('d-none');
            }
            if (cameraVideo) cameraVideo.classList.add('d-none');
            if (cameraInfo) {
                cameraInfo.textContent = '';
                cameraInfo.classList.add('d-none');
            }
            showCameraButtons(false, false);
        });
    }
    if (btnSubmitDisabledReason) {
        btnSubmitDisabledReason.addEventListener('click', function() {
            var msg = 'No data fields are configured for your consent partner. Contact admin.';
            setDataFieldsError(msg);
            showServiceProviderModal(msg, true);
            console.warn('Consent portal submit blocked on client: no partner data fields configured.');
        });
    }
    if (attachmentInput) {
        attachmentInput.addEventListener('change', function() {
            setAttachmentError('');
            var file = (this.files && this.files.length) ? this.files[0] : null;
            if (file && file.size > maxAttachmentSize) {
                setAttachmentError('Attachment must be 10MB or smaller.');
            }
        });
    }
    if (purposeInput) {
        purposeInput.addEventListener('input', function() {
            if ((this.value || '').trim()) {
                setPurposeError('');
            }
        });
    }
    if (dataFieldInputs && dataFieldInputs.length) {
        for (var i = 0; i < dataFieldInputs.length; i++) {
            dataFieldInputs[i].addEventListener('change', function() {
                if (hasSelectedDataField()) {
                    setDataFieldsError('');
                }
            });
        }
    }
    if (btnOpenCamera) {
        btnOpenCamera.addEventListener('click', function() {
            setCameraError('');
            if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
                setCameraError('Camera is not supported on this device/browser.');
                return;
            }
            navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } })
                .then(function(stream) {
                    cameraStream = stream;
                    if (cameraVideo) {
                        cameraVideo.srcObject = stream;
                        cameraVideo.classList.remove('d-none');
                    }
                    showCameraButtons(true, false);
                })
                .catch(function() {
                    setCameraError('Unable to access camera. Please allow camera permission.');
                });
        });
    }

    if (btnCloseCamera) {
        btnCloseCamera.addEventListener('click', function() {
            stopCameraStream();
            if (cameraVideo) cameraVideo.classList.add('d-none');
            showCameraButtons(false, !!(cameraDataInput && cameraDataInput.value));
        });
    }

    if (btnTakeCameraPhoto) {
        btnTakeCameraPhoto.addEventListener('click', function() {
            setCameraError('');
            if (!cameraVideo || !cameraCanvas || !cameraStream) {
                setCameraError('Open camera first.');
                return;
            }
            var width = cameraVideo.videoWidth || 0;
            var height = cameraVideo.videoHeight || 0;
            if (!width || !height) {
                setCameraError('Camera preview not ready. Try again.');
                return;
            }
            cameraCanvas.width = width;
            cameraCanvas.height = height;
            var ctx = cameraCanvas.getContext('2d');
            ctx.drawImage(cameraVideo, 0, 0, width, height);
            var dataUrl = cameraCanvas.toDataURL('image/jpeg', 0.9);
            var base64Part = dataUrl.split(',')[1] || '';
            var approxBytes = Math.floor((base64Part.length * 3) / 4);
            if (approxBytes > maxAttachmentSize) {
                setCameraError('Camera photo must be 10MB or smaller.');
                return;
            }
            if (cameraDataInput) cameraDataInput.value = dataUrl;
            var capturedAt = new Date();
            if (cameraTakenAtInput) cameraTakenAtInput.value = formatDateForOdoo(capturedAt);
            clearCameraLocation();
            if (cameraInfo) {
                cameraInfo.textContent = 'Captured at: ' + capturedAt.toLocaleString() + ' (getting location...)';
                cameraInfo.classList.remove('d-none');
            }
            getCameraLocation(function(hasLocation) {
                if (!cameraInfo) return;
                var message = 'Captured at: ' + capturedAt.toLocaleString();
                if (hasLocation && cameraLatitudeInput && cameraLongitudeInput) {
                    var lat = Number(cameraLatitudeInput.value || 0).toFixed(6);
                    var lon = Number(cameraLongitudeInput.value || 0).toFixed(6);
                    message += ' | Location: ' + lat + ', ' + lon;
                    if (cameraAccuracyInput && cameraAccuracyInput.value) {
                        var accuracy = Number(cameraAccuracyInput.value || 0).toFixed(1);
                        message += ' (± ' + accuracy + ' m)';
                    }
                } else {
                    message += ' | Location unavailable';
                }
                cameraInfo.textContent = message;
                cameraInfo.classList.remove('d-none');
            });
            if (cameraPreview) {
                cameraPreview.src = dataUrl;
                cameraPreview.classList.remove('d-none');
            }
            stopCameraStream();
            if (cameraVideo) cameraVideo.classList.add('d-none');
            showCameraButtons(false, true);
        });
    }

    if (btnRetakeCameraPhoto) {
        btnRetakeCameraPhoto.addEventListener('click', function() {
            if (cameraDataInput) cameraDataInput.value = '';
            if (cameraTakenAtInput) cameraTakenAtInput.value = '';
            clearCameraLocation();
            if (cameraPreview) {
                cameraPreview.src = '';
                cameraPreview.classList.add('d-none');
            }
            if (cameraInfo) {
                cameraInfo.textContent = '';
                cameraInfo.classList.add('d-none');
            }
            setCameraError('');
            showCameraButtons(false, false);
        });
    }
    if (consentForm) {
        consentForm.addEventListener('submit', function(e) {
            var hasError = false;
            var firstErrorMessage = '';
            setPurposeError('');
            setDataFieldsError('');
            setAttachmentError('');
            setCameraError('');

            if (!purposeInput || !(purposeInput.value || '').trim()) {
                setPurposeError('Purpose is required.');
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'Purpose is required.';
            }
            if (dataFieldInputs && dataFieldInputs.length && !hasSelectedDataField()) {
                setDataFieldsError('Select at least one data field.');
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'Select at least one data field.';
            }
            if (!attachmentInput) {
                setAttachmentError('Attachment is required.');
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'Attachment is required.';
            }
            var file = attachmentInput && attachmentInput.files && attachmentInput.files.length ? attachmentInput.files[0] : null;
            if (!file) {
                setAttachmentError('Attachment is required.');
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'Attachment is required.';
            } else if (file.size > maxAttachmentSize) {
                setAttachmentError('Attachment must be 10MB or smaller.');
                hasError = true;
                if (!firstErrorMessage) firstErrorMessage = 'Attachment must be 10MB or smaller.';
            }

            if (cameraDataInput && cameraDataInput.value) {
                var rawBase64 = cameraDataInput.value.split(',')[1] || '';
                var approxBytes = Math.floor((rawBase64.length * 3) / 4);
                if (approxBytes > maxAttachmentSize) {
                    setCameraError('Camera photo must be 10MB or smaller.');
                    hasError = true;
                    if (!firstErrorMessage) firstErrorMessage = 'Camera photo must be 10MB or smaller.';
                }
            }

            if (hasError) {
                console.warn('Consent portal submit blocked on client validation.', {
                    hasPurpose: !!(purposeInput && (purposeInput.value || '').trim()),
                    hasSelectedDataField: hasSelectedDataField(),
                    hasAttachment: !!(attachmentInput && attachmentInput.files && attachmentInput.files.length),
                    dataFieldInputsCount: dataFieldInputs ? dataFieldInputs.length : 0
                });
                showServiceProviderModal(firstErrorMessage || 'Please fix form validation errors.', true);
                e.preventDefault();
            } else {
                console.info('Consent portal submit passed client validation. Submitting form.');
            }
        });
    }

    (function showServerErrorPopup() {
        var errorCode = '';
        try {
            errorCode = new URLSearchParams(window.location.search).get('error') || '';
        } catch (e) {
            errorCode = '';
        }
        if (!errorCode) return;
        var message = errorMessagesByCode[errorCode];
        if (!message) return;
        showServiceProviderModal(message, true);
    })();
    window.addEventListener('beforeunload', function() {
        stopCameraStream();
    });
})();
